# 200 Package Installer - NeoLegal Production Platform

from pathlib import Path

BASE = Path(r"C:\Users\MSI\Desktop\kik_proje")
PY = BASE / ".py"
PKG = PY / "200"

def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nPY_DIR = BASE_DIR / ".py"\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\nCONFIG_DIR = BASE_DIR / "config"\nDOCS_DIR = BASE_DIR / "docs"\nDECISIONS_DIR = DOCS_DIR / "decisions"\n\nPLATFORM_CONFIG_FILE = CONFIG_DIR / "neolegal_platform_config.json"\nPACKAGE_199_MANAGER = PY_DIR / "199_Package_Manager.py"\n\nMIN_DISK_GB = 50\nDEFAULT_TIMEOUT_SECONDS = 3600\n'

UTILS = '# -*- coding: utf-8 -*-\nimport json\nimport shutil\nimport subprocess\nimport sys\nimport time\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n\ndef safe_read(path, limit_chars=500000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n\ndef run_command(command, cwd, timeout=600):\n    started = time.time()\n    try:\n        proc = subprocess.run(\n            command,\n            cwd=str(cwd),\n            capture_output=True,\n            text=True,\n            encoding="utf-8",\n            errors="ignore",\n            timeout=timeout,\n        )\n        return {\n            "executed": True,\n            "timeout": False,\n            "returncode": proc.returncode,\n            "elapsed_seconds": round(time.time() - started, 2),\n            "stdout_tail": proc.stdout[-12000:] if proc.stdout else "",\n            "stderr_tail": proc.stderr[-12000:] if proc.stderr else "",\n            "status": "PASS" if proc.returncode == 0 else "FAIL",\n        }\n    except subprocess.TimeoutExpired as e:\n        return {\n            "executed": True,\n            "timeout": True,\n            "returncode": None,\n            "elapsed_seconds": round(time.time() - started, 2),\n            "stdout_tail": (e.stdout or "")[-12000:] if isinstance(e.stdout, str) else "",\n            "stderr_tail": (e.stderr or "")[-12000:] if isinstance(e.stderr, str) else "",\n            "status": "TIMEOUT",\n        }\n    except Exception as e:\n        return {\n            "executed": True,\n            "timeout": False,\n            "returncode": None,\n            "elapsed_seconds": round(time.time() - started, 2),\n            "stdout_tail": "",\n            "stderr_tail": str(e),\n            "status": "FAIL",\n        }\n'

CONFIG_MANAGER = '# -*- coding: utf-8 -*-\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, CONFIG_DIR, PLATFORM_CONFIG_FILE, MIN_DISK_GB\nfrom utils import now_stamp, now_text, ensure_dirs, disk_free_gb, safe_json, write_json\n\nDEFAULT_CONFIG = {\n    "platform": {\n        "name": "NeoLegal Production Platform",\n        "version": "2.0",\n        "environment": "local",\n        "default_entrypoint": "200_Platform",\n    },\n    "paths": {\n        "base_dir": str(BASE_DIR),\n        "state_dir": str(STATE_DIR),\n        "report_dir": str(REPORT_DIR),\n        "config_dir": str(CONFIG_DIR),\n    },\n    "runtime": {\n        "min_disk_gb": MIN_DISK_GB,\n        "default_timeout_seconds": 3600,\n        "safe_mode_default": True,\n    },\n    "modes": {\n        "status": True,\n        "health": True,\n        "registry": True,\n        "plan": True,\n        "execute": False,\n        "production": False,\n        "maintenance": True,\n    },\n    "quality_gates": {\n        "require_registry_ready": True,\n        "require_platform_ready": True,\n        "require_recovery_clean": True,\n        "require_no_failed_jobs": True,\n    },\n}\n\ndef load_or_create(force=False):\n    ensure_dirs(STATE_DIR, REPORT_DIR, CONFIG_DIR)\n    if PLATFORM_CONFIG_FILE.exists() and not force:\n        data = safe_json(PLATFORM_CONFIG_FILE)\n        if data:\n            return data, False\n    config = dict(DEFAULT_CONFIG)\n    config["created_at"] = now_text()\n    config["updated_at"] = now_text()\n    write_json(PLATFORM_CONFIG_FILE, config)\n    return config, True\n\ndef validate(config):\n    errors = []\n    warnings = []\n    if not config:\n        errors.append("Config yok veya okunamadı.")\n    else:\n        for section in ["platform", "paths", "runtime", "modes", "quality_gates"]:\n            if section not in config:\n                errors.append(f"Eksik bölüm: {section}")\n        if config.get("modes", {}).get("production") is True:\n            warnings.append("Production modu varsayılan açık. Güvenlik için kapalı olmalı.")\n    score = 100 - min(60, len(errors) * 15) - min(30, len(warnings) * 3)\n    score = max(0, score)\n    decision = "CONFIG INVALID" if errors else ("CONFIG REVIEW" if warnings else "CONFIG READY")\n    return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n\ndef run(force=False):\n    ts = now_stamp()\n    config, created = load_or_create(force=force)\n    result = validate(config)\n    state = STATE_DIR / f"200_pkg_config_state_{ts}.json"\n    report = REPORT_DIR / f"200_pkg_config_raporu_{ts}.txt"\n    payload = {"module": "200 Package Config Manager", "created_at": now_text(), "config_created": created, "config_file": str(PLATFORM_CONFIG_FILE), "config": config, "result": result}\n    write_json(state, payload)\n    report.write_text("\\n".join([\n        "="*80,\n        "200 PACKAGE - CONFIG MANAGER",\n        "="*80,\n        f"Score    : {result[\'score\']} / 100",\n        f"Decision : {result[\'decision\']}",\n        f"Created  : {created}",\n        f"Config   : {PLATFORM_CONFIG_FILE}",\n        "",\n        "Dosyalar:",\n        str(PLATFORM_CONFIG_FILE),\n        str(state),\n        str(report),\n    ]), encoding="utf-8")\n    return {"config": config, "result": result, "paths": {"config": str(PLATFORM_CONFIG_FILE), "state": str(state), "report": str(report)}}\n'

CORE = '# -*- coding: utf-8 -*-\nimport sys\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, PACKAGE_199_MANAGER, MIN_DISK_GB\nfrom utils import now_stamp, now_text, ensure_dirs, disk_free_gb, run_command, write_json\nfrom config_manager import run as run_config\n\ndef preflight():\n    return {\n        "package_199_manager_exists": PACKAGE_199_MANAGER.exists(),\n        "status": "PASS" if PACKAGE_199_MANAGER.exists() else "FAIL",\n        "message": "199 Package Manager bulundu." if PACKAGE_199_MANAGER.exists() else "199 Package Manager bulunamadı.",\n    }\n\ndef run_199(mode="all", timeout=600):\n    if mode == "health":\n        args = ["--health"]\n    elif mode == "registry":\n        args = ["--registry"]\n    else:\n        args = ["--all"]\n    return run_command([sys.executable, str(PACKAGE_199_MANAGER)] + args, cwd=BASE_DIR, timeout=timeout)\n\ndef evaluate(pre, config_result, manager_result, free_gb):\n    score = 100\n    errors = []\n    warnings = []\n    if pre["status"] != "PASS":\n        score -= 35\n        errors.append(pre["message"])\n    if config_result["decision"] != "CONFIG READY":\n        score -= 15\n        warnings.append(f"Config sonucu: {config_result[\'decision\']}")\n    if manager_result:\n        if manager_result["status"] != "PASS":\n            score -= 30\n            errors.append("199 Package Manager çalıştırılamadı.")\n        else:\n            out = (manager_result.get("stdout_tail") or "").upper()\n            if "REGISTRY READY" in out and "PLATFORM READY" in out:\n                pass\n            else:\n                score -= 8\n                warnings.append("199 Package çıktısında READY sinyali tam görülmedi.")\n    else:\n        score -= 5\n        warnings.append("199 Package Manager çalıştırılmadı.")\n    if free_gb < MIN_DISK_GB:\n        score -= 20\n        errors.append("Disk alanı düşük.")\n    score = max(0, min(100, score))\n    decision = "CORE BLOCKED" if errors else ("CORE READY" if score >= 95 else "CORE REVIEW")\n    return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n\ndef run(mode="status"):\n    ensure_dirs(STATE_DIR, REPORT_DIR)\n    ts = now_stamp()\n    free = disk_free_gb(BASE_DIR)\n    config_run = run_config(force=False)\n    pre = preflight()\n    mgr = run_199("all" if mode in ["status", "plan"] else mode) if pre["status"] == "PASS" else None\n    result = evaluate(pre, config_run["result"], mgr, free)\n    payload = {"module": "200 Package Core", "created_at": now_text(), "mode": mode, "disk_free_gb": free, "preflight": pre, "config_result": config_run["result"], "manager_result": mgr, "result": result}\n    state = STATE_DIR / f"200_pkg_core_state_{ts}.json"\n    report = REPORT_DIR / f"200_pkg_core_raporu_{ts}.txt"\n    write_json(state, payload)\n    report.write_text("\\n".join([\n        "="*80,\n        "200 PACKAGE - PLATFORM CORE",\n        "="*80,\n        f"Mode     : {mode}",\n        f"Score    : {result[\'score\']} / 100",\n        f"Decision : {result[\'decision\']}",\n        f"Errors   : {len(result[\'errors\'])}",\n        f"Warnings : {len(result[\'warnings\'])}",\n        f"Disk     : {free} GB",\n        "",\n        "Dosyalar:",\n        str(state),\n        str(report),\n    ]), encoding="utf-8")\n    return {"payload": payload, "result": result, "paths": {"state": str(state), "report": str(report)}}\n'

LIFECYCLE = '# -*- coding: utf-8 -*-\nfrom config import STATE_DIR, REPORT_DIR\nfrom utils import now_stamp, now_text, ensure_dirs, write_json\n\ndef run(action="startup"):\n    ensure_dirs(STATE_DIR, REPORT_DIR)\n    ts = now_stamp()\n    allowed = ["startup", "shutdown", "maintenance", "status"]\n    status = "PASS" if action in allowed else "FAIL"\n    result = {\n        "score": 100 if status == "PASS" else 0,\n        "decision": "LIFECYCLE READY" if status == "PASS" else "LIFECYCLE INVALID",\n        "errors": [] if status == "PASS" else [f"Geçersiz lifecycle action: {action}"],\n        "warnings": [],\n    }\n    payload = {"module": "200 Package Lifecycle Manager", "created_at": now_text(), "action": action, "status": status, "result": result}\n    state = STATE_DIR / f"200_pkg_lifecycle_state_{ts}.json"\n    report = REPORT_DIR / f"200_pkg_lifecycle_raporu_{ts}.txt"\n    write_json(state, payload)\n    report.write_text("\\n".join([\n        "="*80,\n        "200 PACKAGE - LIFECYCLE MANAGER",\n        "="*80,\n        f"Action   : {action}",\n        f"Score    : {result[\'score\']} / 100",\n        f"Decision : {result[\'decision\']}",\n        "",\n        "Dosyalar:",\n        str(state),\n        str(report),\n    ]), encoding="utf-8")\n    return {"payload": payload, "result": result, "paths": {"state": str(state), "report": str(report)}}\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom core import run as run_core\nfrom config_manager import run as run_config\nfrom lifecycle import run as run_lifecycle\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--status", action="store_true")\n    parser.add_argument("--health", action="store_true")\n    parser.add_argument("--registry", action="store_true")\n    parser.add_argument("--config", action="store_true")\n    parser.add_argument("--lifecycle", choices=["startup", "shutdown", "maintenance", "status"])\n    parser.add_argument("--plan", action="store_true")\n    args = parser.parse_args()\n\n    if args.config:\n        res = run_config()\n        print("="*80); print("200 PACKAGE CONFIG TAMAMLANDI"); print("="*80)\n        print(f"Decision : {res[\'result\'][\'decision\']} ({res[\'result\'][\'score\']}/100)")\n        print(res["paths"]["report"])\n        return\n\n    if args.lifecycle:\n        res = run_lifecycle(args.lifecycle)\n        print("="*80); print("200 PACKAGE LIFECYCLE TAMAMLANDI"); print("="*80)\n        print(f"Decision : {res[\'result\'][\'decision\']} ({res[\'result\'][\'score\']}/100)")\n        print(res["paths"]["report"])\n        return\n\n    mode = "status"\n    if args.health:\n        mode = "health"\n    elif args.registry:\n        mode = "registry"\n    elif args.plan:\n        mode = "plan"\n\n    res = run_core(mode=mode)\n    print("="*80)\n    print("200 PACKAGE MANAGER TAMAMLANDI")\n    print("="*80)\n    print(f"Mode     : {mode}")\n    print(f"Decision : {res[\'result\'][\'decision\']} ({res[\'result\'][\'score\']}/100)")\n    print(f"Errors   : {len(res[\'result\'][\'errors\'])}")\n    print(f"Warnings : {len(res[\'result\'][\'warnings\'])}")\n    print("")\n    print("Dosyalar:")\n    print(res["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "200"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom manager import main\nif __name__ == "__main__":\n    main()\n'

README = '# 200 Platform Core Package\n\nNeoLegal Production Platform v2.0 çekirdek paketidir.\n\nBileşenler:\n- core.py\n- config_manager.py\n- lifecycle.py\n- manager.py\n- utils.py\n- config.py\n\nAna giriş:\npython ".py\\200_Platform.py" --status\n'

def main():
    PY.mkdir(parents=True, exist_ok=True)
    PKG.mkdir(parents=True, exist_ok=True)

    write("README_200.md", README)
    write("config.py", CONFIG)
    write("utils.py", UTILS)
    write("config_manager.py", CONFIG_MANAGER)
    write("core.py", CORE)
    write("lifecycle.py", LIFECYCLE)
    write("manager.py", MANAGER)

    (PY / "200_Platform.py").write_text(BRIDGE, encoding="utf-8")

    print("="*80)
    print("200 PACKAGE INSTALLER TAMAMLANDI")
    print("="*80)
    print("Kurulan klasör:")
    print(PKG)
    print("")
    print("Şimdi çalıştır:")
    print(r'cd /d C:\Users\MSI\Desktop\kik_proje')
    print(r'python ".py\200_Platform.py" --status')

if __name__ == "__main__":
    main()
